JavaVM->GetEnv()方法可以用来获取当前线程的JNIEnv指针。JavaVM是在JNI_OnLoad方法中传入的，可以通过把JavaVM指针存储到全局变量中，从而在任何线程中访问。

GetEnv方法有两个参数，一个是JNIEnv指针指针的地址，另一个是JNI版本号。JNI版本号可以设置为JNI_VERSION_1_4或者JNI_VERSION_1_6等。在调用GetEnv方法前，需要先判断当前线程是否已经附着到Java虚拟机上。如果没有附着，则需要使用AttachCurrentThread方法进行附着，否则调用GetEnv方法将会返回错误。

例如，以下是在C++中使用JavaVM->GetEnv()方法获取JNIEnv指针的示例代码：

```c++
JavaVM* gJvm; // 全局变量，存储JavaVM指针

JNIEXPORT jint JNICALL JNI_OnLoad(JavaVM* vm, void* reserved) {
    gJvm = vm; // 将JavaVM指针存储到全局变量中
    JNIEnv* env;
    if (vm->GetEnv((void**)&env, JNI_VERSION_1_6) != JNI_OK) {
        // 如果当前线程没有附着到虚拟机上，则附着到虚拟机
        vm->AttachCurrentThread(&env, NULL);
    }
    return JNI_VERSION_1_6;
}

void example() {
    JNIEnv* env;
    gJvm->GetEnv((void**)&env, JNI_VERSION_1_6); // 获取JNIEnv指针
    // 使用JNIEnv指针进行相关操作
}
```

在使用oboe库时，onAudioReady()方法会被频繁地回调，可以使用JNI来调用Kotlin层的方法，以下是示例代码：

Kotlin代码：

```kotlin
class MainActivity : AppCompatActivity() {
    // ...
    external fun onAudioReady(data: ByteArray, length: Int)
    companion object {
        init {
            System.loadLibrary("native-lib")
        }
    }
    // ...
}
```

C++代码：

```c++
jobject gJavaObj = nullptr; // Kotlin对象的全局引用
jmethodID gJavaMethod = nullptr; // Kotlin方法的ID

JNIEXPORT jint JNICALL JNI_OnLoad(JavaVM* vm, void* reserved) {
    JNIEnv* env;
    if (vm->GetEnv((void**) &env, JNI_VERSION_1_6) != JNI_OK) {
        return JNI_ERR;
    }

    // 根据包名和类名获取Java类的引用
    jclass java_cls = env->FindClass("com/example/MainActivity");
    if (java_cls == nullptr) {
        return JNI_ERR;
    }
    // 保存Kotlin对象的全局引用
    gJavaObj = env->NewGlobalRef(obj);

    // 根据方法名和签名获取Java方法的ID
    gJavaMethod = env->GetMethodID(java_cls, "onAudioReady", "([BI)V");
    if (gJavaMethod == nullptr) {
        return JNI_ERR;
    }

    return JNI_VERSION_1_6;
}

JNIEXPORT void JNICALL
Java_com_example_MyOboeCallback_onAudioReady(JNIEnv *env, jobject thiz, jobject audio_buffer, jint num_frames) {
    // 将Java的字节数组转换为C++的char指针
    jbyte* buffer = static_cast<jbyte*>(env->GetDirectBufferAddress(audio_buffer));
    int buffer_len = env->GetDirectBufferCapacity(audio_buffer);

    // 调用Kotlin层的方法
    env->CallVoidMethod(gJavaObj, gJavaMethod, audio_buffer, buffer_len);
}
```

在JNI_OnLoad()方法中，程序首先通过FindClass()方法获取Kotlin类的引用，然后创建全局引用。通过GetMethodID()方法获取Kotlin方法的ID。在onAudioReady()回调方法中，将Java层的字节数组转换为C++的char指针，调用CallVoidMethod()方法回调Kotlin层的方法。

需要注意的是，回调Kotlin层的方法应该谨慎使用，确保对线程的正确控制。在JNI中，所有的方法调用都应该在正确的线程中进行，不能直接在oboe回调的线程中调用。可以使用AttachCurrentThread()方法将当前线程附加到Java虚拟机上，然后调用CallVoidMethod()方法。

确实，我犯了一个错误，onAudioReady是oboe库C++中的回调方法。在C++中回调Kotlin层的方法，需要将Kotlin的虚拟机环境传递给C++，以便C++能够访问Kotlin层的对象和方法。

以下是示例代码：

Kotlin代码：

```kotlin
class MainActivity : AppCompatActivity() {
    // ...
    val myOboeCallback = MyOboeCallback()
    // ...

    inner class MyOboeCallback {

        external fun onAudioReady(data: ByteArray, length: Int)

        companion object {
            init {
                System.loadLibrary("native-lib")
            }
        }
    }
    // ...
}
```

C++代码：

```c++
#include <jni.h>
#include <oboe/Oboe.h>

JavaVM* gJvm = nullptr; // Kotlin虚拟机环境
jobject gJavaObj = nullptr; // Kotlin对象的全局引用
jmethodID gJavaMethod = nullptr; // Kotlin方法的ID

class MyOboeCallback : public oboe::AudioStreamDataCallback {
    oboe::DataCallbackResult onAudioReady(oboe::AudioStream* stream, void* audio_data,
        int32_t num_frames) override {
        jbyte* buffer = static_cast<jbyte*>(audio_data);
        int buffer_len = num_frames * stream->getBytesPerFrame();

        // 获取JNIEnv指针
        JNIEnv* env = nullptr;
        gJvm->AttachCurrentThread(&env, nullptr);

        // 把Audio数据传递到Kotlin层
        jbyteArray audio_buffer = env->NewByteArray(buffer_len);
        env->SetByteArrayRegion(audio_buffer, 0, buffer_len, reinterpret_cast<jbyte*>(buffer));
        env->CallVoidMethod(gJavaObj, gJavaMethod, audio_buffer, buffer_len);

        // 释放局部引用
        env->DeleteLocalRef(audio_buffer);

        // 释放JNIEnv指针
        gJvm->DetachCurrentThread();

        return oboe::DataCallbackResult::Continue;
    }
};

JNIEXPORT jint JNICALL JNI_OnLoad(JavaVM* vm, void* reserved) {
    JNIEnv* env;
    if (vm->GetEnv((void**) &env, JNI_VERSION_1_6) != JNI_OK) {
        return JNI_ERR;
    }

    // 根据包名和类名获取Java类的引用
    jclass java_cls = env->FindClass("com/example/MainActivity");
    if (java_cls == nullptr) {
        return JNI_ERR;
    }

    // 获取Kotlin虚拟机环境
    gJvm = vm;

    // 保存Kotlin对象的全局引用
    jmethodID constructor = env->GetMethodID(java_cls, "<init>", "()V");
    gJavaObj = env->NewGlobalRef(env->NewObject(java_cls, constructor));

    // 根据方法名和签名获取Java方法的ID
    gJavaMethod = env->GetMethodID(java_cls, "onAudioReady", "([BI)V");
    if (gJavaMethod == nullptr) {
        return JNI_ERR;
    }

    return JNI_VERSION_1_6;
}

extern "C" JNIEXPORT void JNICALL
Java_com_example_MyOboeCallback_native_1createStream(JNIEnv *env, jobject thiz, jint sample_rate,
        jint channel_count, jint data_format, jint performance_mode, jint sharing_mode) {
    oboe::AudioStreamBuilder builder;
    builder.setChannelCount(channel_count)
            .setFormat(static_cast<oboe::AudioFormat>(data_format))
            .setPerformanceMode(static_cast<oboe::PerformanceMode>(performance_mode))
            .setSharingMode(static_cast<oboe::SharingMode>(sharing_mode))
            .setSampleRate(sample_rate)
            .setDataCallback(new MyOboeCallback())
            .setErrorCallback(oboe::ErrorCallback::defaultErrorCallback);
    oboe::AudioStream *stream;
    builder.openStream(&stream);
    stream->start();
}
```

该示例代码在C++中实现了MyOboeCallback类来回调oboe库中的onAudioReady()方法。在onAudioReady()方法中，获取JNIEnv指针，然后将audio数据传递到Kotlin层，最后释放所有的局部引用和JNIEnv指针。JDNI_OnLoad()方法中，获取Kotlin的虚拟机环境，并创建全局引用。在native_createStream()函数中，创建oboe的音频流，将MyOboeCallback对象传递到onAudioReady()方法中。注意，在使用JNI进行跨语言交互时，要特别注意线程安全性和环境的正确性。

当gJavaObj不再使用时，必须手动释放它。如果gJavaObj是一个全局引用，则使用DeleteGlobalRef()方法进行释放。如果是局部引用，则使用DeleteLocalRef()方法进行释放。局部引用不需要手动删除，JNI会自动删除。在释放全局引用时，需要谨慎确保保留足够的引用，并避免出现僵尸引用，否则可能会导致应用程序崩溃或者内存泄漏。

在本示例代码中，全局引用gJavaObj在JNI_OnLoad()方法中创建，并在JNI_OnUnload()方法中进行释放。如果程序中没有调用JNI_OnUnload()方法，则需要在程序退出前手动释放全局引用。在释放全局引用时，可以使用SetGlobalRef()函数将全局引用设置为空指针，以避免出现悬空引用。

以下是示例代码：

```c++
// 释放全局引用
void releaseGlobalRefs(JNIEnv* env) {
    if (gJavaObj != nullptr) {
